import{_ as i,o,c as t,a6 as a}from"./chunks/framework.CBMw8OFm.js";const u=JSON.parse('{"title":"CSRF","description":"","frontmatter":{},"headers":[],"relativePath":"security/csrf.md","filePath":"security/csrf.md","lastUpdated":1772606493000}'),l={name:"security/csrf.md"};function s(r,e,c,n,d,p){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="csrf" tabindex="-1">CSRF <a class="header-anchor" href="#csrf" aria-label="Permalink to “CSRF”">​</a></h1><p>CSRF (Cross-Site Request Forgery) 是欺騙使用者在信任網站進行非預期操作</p><h2 id="攻擊方式" tabindex="-1">攻擊方式 <a class="header-anchor" href="#攻擊方式" aria-label="Permalink to “攻擊方式”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>CSRF 是針對 cookie 和 session 的攻擊方式<br> 課程範例架構是前後端分離 + JWT 認證，所以不需要進行 CSRF 防護</p></div><ol><li>使用者進入已登入的安全網站 <code>bank.com</code>，瀏覽器保存 cookie 驗證資訊，下次來不用重新登入，且之後瀏覽時都會帶上</li><li>在未登出的狀況下，進入在惡意網站</li><li>惡意網站可能有一張圖片， <code>&lt;img src=&quot;bank.com/transfer?to=hacker&amp;amount=10000&quot; style=&quot;display:none&quot;&gt;</code></li><li>瀏覽器讀取圖片，發送請求</li><li>由於目標是 <code>bank.com</code>，所以點連結時會瀏覽器會自動帶入 cookie</li><li>轉帳成功</li></ol><h2 id="防護措施" tabindex="-1">防護措施 <a class="header-anchor" href="#防護措施" aria-label="Permalink to “防護措施”">​</a></h2><ul><li>Origin: 後端檢查 origin，判斷是不是從自己的網站發出的請求</li><li>SameSite=Strict: 設定 cookie 自動帶入方式，只有從第一方網站瀏覽時才自動帶入</li><li>CSRF Token 表單驗證: <ol><li>使用者登入後，後端產生 session</li><li>進入表單頁面時，後端產生一個 token，存入 session</li><li>伺服器將 token 傳給前端，通常會放在 <code>&lt;input type=&quot;hidden&quot;&gt;</code></li><li>送出表單時，前端將 token 傳送給後端</li><li>後端驗證 session 保存的 token 是否和前端傳入的一致</li></ol></li></ul>',7)])])}const _=i(l,[["render",s]]);export{u as __pageData,_ as default};
